// HasPriceBookItems applies the HasEdge predicate on the "price_book_items" edge.
func HasPriceBookItems() predicate.CatalogItem {
	return predicate.CatalogItem(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, PriceBookItemsTable, PriceBookItemsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasPriceBookItemsWith applies the HasEdge predicate on the "price_book_items" edge with a given conditions (other predicates).
func HasPriceBookItemsWith(preds ...predicate.PriceBookItem) predicate.CatalogItem {
	return predicate.CatalogItem(func(s *sql.Selector) {
		step := newPriceBookItemsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.CatalogItem) predicate.CatalogItem {
	return predicate.CatalogItem(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.CatalogItem) predicate.CatalogItem {
	return predicate.CatalogItem(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.CatalogItem) predicate.CatalogItem {
	return predicate.CatalogItem(sql.NotPredicates(p))
}
